use axum::{
    routing::{get, post},
    Router,
};
use sqlx::postgres::PgPoolOptions;
use std::time::Duration;
use tokio::net::TcpListener;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    dotenv::dotenv().ok();

    let database_url = std::env::var("DATABASE_URL")?;

    // Create connection pool
    let pool = PgPoolOptions::new()
        .max_connections(5)
        .acquire_timeout(Duration::from_secs(30))
        .connect(&database_url)
        .await?;

    // Run migrations
    sqlx::migrate!("./migrations")
        .run(&pool)
        .await?;

    println!("✓ Connected to database and ran migrations");

    // Create router with handlers
    let app = Router::new()
        .route("/health", get(health))
        .route("/entries", post(handlers::add_entry))
        .route("/entries", get(handlers::list_entries))
        .route("/entries/:id", get(handlers::get_entry))
        .route("/verify", get(handlers::verify_chain))
        .with_state(pool.clone());

    // Run server
    let listener = TcpListener::bind("127.0.0.1:3000")
        .await?;

    println!("✓ vaultlog API listening on {}", listener.local_addr()?);

    axum::serve(listener, app)
        .await?;

    Ok(())
}

